VALUES
  ('optometrist-moex-03654', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於鏡片沉澱（lens deposition）的敘述，下列何者最不正確？', '["同樣的配戴週期與時間，低含水水膠鏡片較高含水水膠鏡片，容易產生蛋白吸附與沉澱", "同樣材料鏡片，連續配戴型（extended wear）較日戴型（daily wear）容易產生沉澱問題", "淚水分泌不足的乾眼患者較淚液分泌正常患者，容易產生鏡面沉澱", "瞼板腺分泌功能不佳者較正常患者，容易產生鏡片沉澱"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03655', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一般隱形眼鏡配戴過夜，可能導致角膜內何種物質堆積，引起角膜水腫？', '["膽固醇", "糖分", "乳酸", "鐵質"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03656', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列那一角膜病變與配戴隱形眼鏡時引起的角膜缺氧無關？', '["角膜淺凹（dellen）", "微小囊腫（microcysts）", "角膜基質水腫（stromal edema）", "內皮細胞多狀症（polymegathism）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03657', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於圓錐角膜患者的硬式隱形眼鏡驗配，下列敘述何者錯誤？', '["以頂端軸承法驗配（apical bearing），可能造成角膜上皮反覆摩擦破損", "以頂端清除法驗配（apical clearance），則可能因過多淚水淤積於光學區，導致視力不穩定", "以三點接觸法驗配（three point touch），鏡片與角膜的接觸點分別在角膜頂尖（apex）與三、九點邊緣 （peripheral edge）， 可避免鏡片過度摩擦角膜頂尖", "在頂端軸承法、頂端清除法、三點接觸法等驗配方式均無法達到良好視力矯正效果與舒適度，可考慮 使用大直徑鞏膜鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03658', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '角膜水平直徑為12.2 mm，角膜平弧為43.0 D；陡弧為43.5 D，下列那一個軟式隱形眼鏡鏡片直徑與弧度 的組合，最適合此患者配戴？', '["鏡片直徑14.2 mm，基弧7.8 mm", "鏡片直徑12.2 mm，基弧7.8 mm", "鏡片直徑14.2 mm，基弧8.6 mm", "鏡片直徑12.2 mm，基弧8.6 mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03659', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '假定配戴-4.00 DS的隱形眼鏡試戴片，進行插片驗光（over-refraction），再加上+6.00 DS的眼鏡鏡片可 矯正至最佳視力。則換算後患者最終隱形眼鏡度數處方應為下列何者？', '["+1.00 DS", "+1.50 DS", "+2.00 DS", "+2.50 DS ×"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03660', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴者的驗光度數為-3.50DS/-1.25DC 180，廠商所設計的軟式散光隱形眼鏡試片的雷射刻度（reference marking）在6點鐘方向，病人試戴鏡片時，刻度停留在7點鐘位置，下列那一個隱形鏡片度數最適合這 位配戴者？ × × × ×', '["-3.50DS/-1.00DC 150", "-3.50DS/-1.00DC 030", "-3.50DS/-1.25DC 150", "-3.50DS/-1.25DC 030"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03661', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '病人的硬式隱形眼鏡經過檢查，螢光染色型態顯現鏡片頂端觸碰（apical touch），鏡片規格為7.70 mm基 弧／9.6 mm直徑／-3.75 DS度數，經過重新設計，決定將基弧改為7.60 mm但維持原來直徑，新的鏡片 度數應為：', '["-3.50 DS", "-3.25 DS", "-4.00 DS", "-4.25 DS × ×"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03662', 'optometrist', 'optometrist-moex-106-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '眼鏡度數-3.50DS/-2.75DC 180 若配戴一廠牌的軟式散光鏡片-3.75DS/-2.25DC 180，其中心定位及滑動 × 良好，且穩定向左偏移10度，若訂鏡片-3.75DS/-2.25DC 010配戴後，正常情形下鏡片表現應為：', '["中心定位及滑動良好，且穩定向左偏移10度", "中心定位及滑動良好，且穩定沒有偏移", "中心定位及滑動良好，且穩定向右偏移10度", "鏡片滑動非常大"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:56+00:00", "source_pdf_sha1": "43136df1aeb4", "answer_pdf_sha1": "f9cf08f73c11", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
